int edgeCount(std::vector<int> const& A, size_t N)
{
    // OpenMP parallel for with reduction on the count accumulator.
    // Use schedule(static) for equal distribution of the outer loop
    // across the available threads.  The inner loop is trivial, so
    // we keep the classic two‑level loop structure for clarity.
    int count = 0;
