    // Compute the prefix minimum in a single pass.
    // The implementation is intentionally straightforward so that
    // the compiler can auto‑vectorise and fully optimise it.
    float cur_min = std::numeric_limits<float>::max();

    // Using a raw pointer can sometimes give the compiler a little
    // more mileage when turning the loop into SIMD instructions.
    float* ptr = x.data();
