```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <numeric>

int componentCount(const std::vector<int>& A, size_t N)
{
    /* Disjoint Set Union (Union‑Find) implementation.
       The graph is undirected, so any edge A[i][j]==1 (i<j)
       connects the vertices i and j. */
    std::vector<size_t> parent(N);
    std::iota(parent.begin(), parent.end(), 0);

    // Find with path compression
    auto find = [&](size_t x, auto&& find_ref) -> size_t {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    };

    // Union by rank (simple union)
    for (size_t i = 0; i < N; ++i) {
        const size_t base = i * N;
        for (size_t j = i + 1; j < N; ++j) {            // upper triangle
            if (A[base + j]) {                          // adjacency == 1
                size_t ri = find(i, find);
                size_t rj = find(j, find);
                if (ri != rj) parent[ri] = rj;
            }
        }
    }

    // Count distinct roots
    size_t count = 0;
    for (size_t i = 0; i < N; ++i) {
        if (parent[i] == i) ++count;
    }
    return static_cast<int>(count);
}
