#pragma once
#include <vector>
#include <limits>
#include <cstdint>

/* Return the largest sum of any contiguous subarray in the vector x.
   Uses Kadane's algorithm (O(n)), which produces the same result as the
   original O(n²) brute‑force approach while being far faster.
   amd fallback to O(n²) when the vector is too small to benefit from
   the linear algorithm (keeps the behaviour identical for tiny inputs). */
inline int maximumSubarray(const std::vector<int>& x) {
    if (x.empty()) return 0;

    // For very small vectors the overhead of the linear algorithm
    // can be larger than the simple quadratic scan.  The original
    // implementation does an O(n²) walk, so we mimic that for n < 64.
    constexpr std::size_t HALF_CUTOFF = 64;
    if (x.size() < HALF_CUTOFF) {
        int largestSum = std::numeric_limits<int>::lowest();
        for (std::size_t i = 0; i < x.size(); ++i) {
            int currSum = 0;
            for (std::size_t j = i; j < x.size(); ++j) {
                currSum += x[j];
                if (currSum > largestSum) largestSum = currSum;
            }
        }
        return largestSum;
    }

    // Kadane's algorithm (linear time)
    int best = x[0];
    int current = x[0];
    for (std::size_t i = 1; i < x.size(); ++i) {
        current = std::max(x[i], current + x[i]);
        if (current > best) best = current;
    }
    return best;
}
