/*
 * Compute z = alpha*x + y where x and y are sparse vectors.
 * The result is accumulated into an already existing dense vector z.
 * This implementation is purely parallel and therefore faster on
 * multi‑core systems while preserving the exact arithmetic behaviour.
 */
inline void sparseAxpy(double alpha,
                       std::vector<Element> const& x,
                       std::vector<Element> const& y,
                       std::vector<double>& z)
{
    // Parallel accumulation of the alpha*x part.
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(x.size()); ++i) {
        // The atomic is required because multiple threads may try
        // to update the same index concurrently.
        #pragma omp atomic
        z[x[i].index] += alpha * x[i].value;
    }

    // Parallel accumulation of the y part.
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(y.size()); ++i) {
        #pragma omp atomic
        z[y[i].index] += y[i].value;
    }
}
