```cpp
// Optimised implementation of reversePrefixSum
#pragma once
#include <vector>
#include <numeric>
#include <algorithm>
#include <iterator>
#include <cstddef>
#include <omp.h>

inline void reversePrefixSum(const std::vector<int>& x, std::vector<int>& output)
{
    const std::size_t n = x.size();
    output.resize(n);

    // Ensure output large enough
    if (n == 0) return;

    // Compute the reverse inclusive scan.
    // We use a manual loop to avoid the temporary vector and to allow
    // a straightforward OpenMP reduction on small chunks.
    int runningSum = 0;

    // Parallel decomposed loop with chunk size to balance work
    #pragma omp parallel
    {
        int localSum = 0;
        const int id  = omp_get_thread_num();
        const int nth = omp_get_num_threads();

        // Determine work range for this thread
        const std::size_t chunk = (n + nth - 1) / nth;
        const std::size_t start = id * chunk;
        const std::size_t end   = std::min(start + chunk, n);

        // Forward loop over the chunk (descending in the original vector)
        for (std::size_t i = start; i < end; ++i) {
            const std::size_t idx = n - 1 - i;          // index in original vector
            localSum += x[idx];
            output[n - 1 - i] = localSum;
        }

        // Reduce partial sums to get correct prefix values for earlier chunks
        #pragma omp atomic
        runningSum += localSum;
    }

    // Final pass to add the partial sums from earlier chunks
    // Now runningSum holds the sum of the entire vector
    int offset = 0;
    for (std::size_t i = 0; i < n; ++i) {
        offset = output[i];
        output[i] = runningSum - offset + output[i];
        runningSum -= offset;
    }
}
