```cpp
#pragma once
#include <vector>
#include <limits>
#include <cstddef>
#include <cstdint>

/* Return the length of the shortest path from source to dest in the undirected graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row-major form.
   The graph is assumed to be connected and undirected.
*/
inline int shortestPathLength(const std::vector<int>& A, std::size_t N,
                               int source, int dest)
{
    // Use a compact byte array for visited flags.
    std::vector<char> visited(N, 0);
    // Reserve a flat queue of indices: maximum N elements.
    std::vector<int> queue;
    queue.reserve(N);
    std::size_t head = 0;

    visited[source] = 1;
    queue.push_back(source);

    int distance = 0;            // current hop count
    int levelEnd = 1;             // index in queue where current level ends

    while (head < queue.size() && head < levelEnd) {
        while (head < levelEnd) { // process current BFS level
            int cur = queue[head++];
            if (cur == dest) return distance;

            // iterate over all neighbors in the row-major matrix
            int base = cur * static_cast<int>(N);
            for (int i = 0; i < static_cast<int>(N); ++i) {
                if (A[base + i] && !visited[i]) {
                    visited[i] = 1;
                    queue.push_back(i);
                }
            }
        }
        // move to the next level
        distance++;
        levelEnd = queue.size();
    }

    // Graph is assumed connected, but return a sentinel if not found.
    return std::numeric_limits<int>::max();
}
