#pragma once
#include <array>
#include <vector>
#include <omp.h>

struct Point {
   double x, y;
};

/*
 * Count the number of cartesian points in each quadrant.
 * The vector points contains a list of `Point` objects.
 * Store the counts in `bins`.
 *
 * Example:
 *   input: [{x=1.5, y=0.1}, {x=-3, y=1.1}, {x=5, y=9}, {x=1.5, y=-1},
 *           {x=3, y=-7}, {x=0.1, y=2}]
 *   output: [3, 1, 0, 2]
 */
void countQuadrants(std::vector<Point> const& points, std::array<size_t, 4>& bins) {
    // Reset bins
    bins.fill(0);

    // Each thread gets its own local counter array to avoid atomic contention
    #pragma omp parallel
    {
        std::array<size_t, 4> local = {0, 0, 0, 0};

        #pragma omp for nowait
        for (size_t i = 0; i < points.size(); ++i) {
            const auto& p = points[i];
            if (p.x >= 0.0) {
                if (p.y >= 0.0) {
                    ++local[0];          // Q1
                } else {
                    ++local[3];          // Q4
                }
            } else {
                if (p.y >= 0.0) {
                    ++local[1];          // Q2
                } else {
                    ++local[2];          // Q3
                }
            }
        }

        // Merge thread-local counters into the global result
        #pragma omp critical
        {
            for (int j = 0; j < 4; ++j) {
                bins[j] += local[j];
            }
        }
    }
}
