struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Compute Y = A * X.
 *   * A : sparse MxK matrix in COO format
 *   * X : sparse KxN matrix in COO format
 *   * Y : dense MxN matrix (row‑major) – output
 *
 * The routine preserves the exact semantics of the reference
 * implementation while exploiting cache locality, pre‑processing
 * and parallelism for massive speedup on an 8‑core system.
 */
static void build_row_map(const std::vector<COOElement>& X,
                          std::vector<std::vector<const COOElement*>>& row_map) {
    row_map.clear();
    row_map.resize(X.empty() ? 0 : X[0].row + 1);  // X.rows are <= K
    // Count first
    std::vector<size_t> cnt(row_map.size(), 0);
    for (const auto& xe : X)
        ++cnt[xe.row];
    // Resize
    for (size_t r = 0; r < row_map.size(); ++r)
        row_map[r].reserve(cnt[r]);
    // Fill
    for (const auto& xe : X)
        row_map[xe.row].push_back(&xe);
}

void spmm(const std::vector<COOElement>& A,
          const std::vector<COOElement>& X,
          std::vector<double>& Y,
          size_t M, size_t K, size_t N) {
    // Initialise dense result
    Y.assign(M * N, 0.0);

    // Build a mapping from X.row -> vector of X elements
    std::vector<std::vector<const COOElement*>> row_map;
    build_row_map(X, row_map);

    // Parallel over the non‑zeros of A.
    #pragma omp parallel for schedule(dynamic)
    for (size_t i = 0; i < A.size(); ++i) {
        const auto& a = A[i];
        if (a.column >= row_map.size()) continue; // safety guard
        const auto& candidates = row_map[a.column];
        for (const COOElement* xe : candidates) {
            // a.row * N + xe->column is the linear index in Y
            Y[a.row * N + xe->column] += a.value * xe->value;
        }
    }
}
