/*
 * Compute the discrete Fourier transform of x. Store the result in output.
 * Example:
 *   input:  [1, 4, 9, 16]
 *   output: [30+0i, -8-12i, -10-0i, -8+12i]
 */
inline void dft(const std::vector<double> &x,
                std::vector<std::complex<double>> &output) {
    const std::size_t N = x.size();
    output.assign(N, std::complex<double>(0.0, 0.0));

    const double two_pi = 2.0 * M_PI;
    const double factor = two_pi / static_cast<double>(N);

    // Parallelize over k (outer loop). Each thread keeps its own accumulator.
    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k) {
        std::complex<double> sum(0.0, 0.0);
        for (std::size_t n = 0; n < N; ++n) {
            const double angle = factor * static_cast<double>(n * k);
            const double c_re = std::cos(angle);
            const double c_im = -std::sin(angle);
            sum += std::complex<double>(x[n] * c_re, x[n] * c_im);
        }
        output[k] = sum;
    }
}
