   Each element of `input` is averaged with its two neighbors and stored
   in the corresponding element of `output`. Boundaries are treated as
   zero. */
inline void jacobi1D(std::vector<double> const& input, std::vector<double> &output)
{
    const size_t n  = input.size();
    if (n == 0) return;

    const double*  ip = input.data();   // input pointer
          double*   op = output.data(); // output pointer

    /* Parallelise the loop, capturing `n` by value.
       OpenMP directives are cheap for large `n` and keep the
       computation data‑local. */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < n; ++i) {
        double sum = ip[i];               // middle value

        if (i > 0)   sum += ip[i-1];       // left neighbour
        if (i + 1 < n) sum += ip[i+1];     // right neighbour

        op[i] = sum / 3.0;                 // store result
    }
}
