#pragma once
#include <vector>
#include <cstdint>
#include <omp.h>

/* Compute the inclusive prefix sum of the vector `x` into `output`.
 *
 * This implementation performs the operation in parallel using 8 threads
 * (or the number of threads set for OpenMP).  The algorithm works in two
 * phases:
 *
 *   1. Each thread computes a local inclusive scan on its chunk of the
 *      input and also records the total sum of that chunk.
 *   2. A prefix sum of the chunk totals is performed serially to obtain the
 *      offset that must be added to each thread’s results.
 *
 * The final output is identical to the one produced by
 * `std::inclusive_scan` on the entire vector.
 */
inline void prefixSum(const std::vector<int64_t>& x, std::vector<int64_t>& output)
{
    const std::size_t N = x.size();
    output.resize(N);

    if (N == 0) return;

    const int num_threads = 8;          // #threads available in the environment
    const std::size_t chunk_size = (N + num_threads - 1) / num_threads;

    std::vector<int64_t> block_sums(num_threads, 0);

    /* Phase 1: local scans */
#pragma omp parallel num_threads(num_threads)
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * chunk_size;
        const std::size_t end   = std::min(start + chunk_size, N);

        if (start >= end) { block_sums[tid] = 0; return; }

        int64_t sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            sum += x[i];
            output[i] = sum;
        }
        block_sums[tid] = sum;
    }

    /* Phase 2: compute offsets for each block */
    int64_t offset = 0;
    for (int i = 0; i < num_threads; ++i) {
        const int64_t block_total = block_sums[i];
        block_sums[i] = offset;        // now holds the offset for this block
        offset += block_total;
    }

    /* Phase 3: add block offsets to each element (parallel) */
#pragma omp parallel for num_threads(num_threads)
    for (std::size_t i = 0; i < N; ++i) {
        const int tid = i / chunk_size;
        output[i] += block_sums[tid];
    }
}
