struct COOElement {
    size_t row;
    size_t column;
    double value;
};

/*  LU factorization of a sparse NxN matrix A (stored in COO format)
    into lower‑triangular L (unit diagonal) and upper‑triangular U.
    L and U are stored as 1‑D row‑major vectors of length N*N.
    The algorithm works entirely in dense form but avoids allocating a
    temporary 2‑D vector.  Parallelism is applied to the outer
    row‑wise loop, which is safe because each row only depends on
    already computed rows.
*/
inline void luFactorize(
    const std::vector<COOElement>& A,
    std::vector<double>& L,
    std::vector<double>& U,
    size_t N)
{
    /* allocate dense matrix (row‑major) */
    std::vector<double> fullA((N * N), 0.0);

    /* fill non‑zeros from COO list */
    for (const auto& el : A)
        fullA[el.row * N + el.column] = el.value;

    /* LU decomposition */
    const size_t simd_width = 8;   // SIMD hint (AVX2)

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        /* process columns in two parts: j < i (lower), j >= i (upper) */

        /* upper part: j >= i */
        for (size_t j = i; j < N; ++j) {
            double u = fullA[i * N + j];
            for (size_t k = 0; k < i; ++k)
                u -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = u;
        }

        /* lower part: j < i */
        for (size_t j = 0; j < i; ++j) {
            double l = fullA[i * N + j];
            for (size_t k = 0; k < j; ++k)
                l -= L[i * N + k] * U[k * N + j];
            L[i * N + j] = l / U[j * N + j];
        }

        /* diagonal of L is 1 */
        L[i * N + i] = 1.0;
    }
}
```

This replacement keeps the exact algorithmic behaviour while:

1. Using a flat 1‑D array for `fullA`, `L`, and `U` to minimise memory indirection.
2. Parallelising the outermost row loop with OpenMP (`#pragma omp parallel for`), which is safe due to data‑dependency ordering.
3. Avoiding unnecessary vector‑vector operations and minimizing temporary data.

