#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

/* -------------------------------------------------------------------------
   Sparse linear solve
   --------------------------------------------------------------------------
   The solver builds a dense representation of the matrix from the COO
   data, performs a standard Gaussian elimination with partial pivoting
   and then back substitution.  The implementation below:
   * uses a 1‑D flat array for the matrix to improve cache locality
   * leverages OpenMP to parallelise the construction of the dense matrix
   * performs the same operations as the original reference implementation
   * keeps the function signature unchanged.
   -------------------------------------------------------------------------- */

struct COOElement {
    size_t row, column;
    double value;
};

inline double abs_val(double v) noexcept { return v < 0 ? -v : v; }

void solveLinearSystem(
    std::vector<COOElement> const& A,
    std::vector<double> const&   b,
    std::vector<double> &        x,
    size_t                       N)
{
    /* 1‑D dense matrix */
    std::vector<double> mat(N * N, 0.0);
    std::vector<double> b_copy = b;

    /* Build the matrix in parallel */
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const auto &e = A[idx];
        mat[e.row * N + e.column] = e.value;
    }

    /* Gaussian elimination with partial pivoting */
    for (size_t i = 0; i < N; ++i) {
        /* Pivot search */
        double maxEl = abs_val(mat[i * N + i]);
        size_t maxRow = i;
        for (size_t k = i + 1; k < N; ++k) {
            double val = abs_val(mat[k * N + i]);
            if (val > maxEl) {
                maxEl = val;
                maxRow = k;
            }
        }
        /* Swap rows i and maxRow */
        if (maxRow != i) {
            for (size_t k = i; k < N; ++k) {
                std::swap(mat[maxRow * N + k], mat[i * N + k]);
            }
            std::swap(b_copy[maxRow], b_copy[i]);
        }

        /* Eliminate rows below */
        double pivot = mat[i * N + i];
        for (size_t k = i + 1; k < N; ++k) {
            double factor = -mat[k * N + i] / pivot;
            for (size_t j = i; j < N; ++j) {
                if (i == j)
                    mat[k * N + j] = 0.0;
                else
                    mat[k * N + j] += factor * mat[i * N + j];
            }
            b_copy[k] += factor * b_copy[i];
        }
    }

    /* Back substitution */
    x.assign(N, 0.0);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = b_copy[i];
        for (int j = static_cast<int>(i) + 1; j < static_cast<int>(N); ++j) {
            sum -= mat[i * N + j] * x[j];
        }
        x[i] = sum / mat[i * N + i];
    }
}
