inline bool xorContains(const std::vector<int>& x, const std::vector<int>& y, int val)
{
    // Search in x
    const bool foundInX = [&](){
        for (auto it = x.cbegin(); it != x.cend(); ++it)
            if (*it == val) return true;
        return false;
    }();

