/*
 * LU Factorisation (in‑place, no pivoting).
 *
 * A is an N×N matrix in row‑major order.
 * The output overwrites A with the combined representation:
 *      L (unit‑diagonal) occupies the strict lower part,
 *      U occupies the upper triangular part including the diagonal.
 *
 * The implementation uses pointer arithmetic for speed, and it
 * parallelises the outer i‑loop with OpenMP.  All arithmetic
 * remains single‑precision double as in the original code.
 */
inline void luFactorize(std::vector<double> &A, const std::size_t N)
{
    const std::size_t stride = N;          // row stride
    const double *const Abeg = A.data();  // base address

    // No pivoting assumed; if a zero pivot occurs the division will
    // produce INF/NAN, which matches the behaviour of the original.
#pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k) {
        const double *rowk = Abeg + k * stride;       // A[k][*]
        double denom = rowk[k];                      // pivot a_kk
        // Compute multipliers for rows below k
        for (std::size_t i = k + 1; i < N; ++i) {
            double *rowi = Abeg + i * stride;       // A[i][*]
            double factor = rowi[k] / denom;        // a_ik / a_kk
            rowi[k] = factor;                       // store L_ik
            // update the trailing sub‑matrix row i
            for (std::size_t j = k + 1; j < N; ++j) {
                rowi[j] -= factor * rowk[j];
            }
        }
    }
}
