#include <omp.h>

struct Point
{
    double x, y;
};

/* Fast cross product */
inline double cross(const Point &a, const Point &b, const Point &c) noexcept
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Fast Euclidean distance – avoids pow, uses sqrt only once */
inline double dist(const Point &a, const Point &b) noexcept
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

/* Return the perimeter of the convex hull of `points`.
   Implements Andrew's monotone chain in O(N log N). */
double convexHullPerimeter(const std::vector<Point> &points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    /* Sort points lexicographically (x, then y). */
    std::vector<Point> pts(points);                         // Make a mutable copy
    std::sort(pts.begin(), pts.end(),
              [](const Point &a, const Point &b) noexcept
              { return a.x < b.x || (a.x == b.x && a.y < b.y); });

    /* Build the convex hull */
    std::vector<Point> hull;
    hull.reserve(n * 2);

    /* Lower hull */
    for (const auto &p : pts)
    {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull.back(), p) <= 0)
            hull.pop_back();
        hull.push_back(p);
    }

    /* Upper hull */
    const std::size_t lower_size = hull.size();
    for (std::size_t i = 1; i < n; ++i)
    {
        const Point &p = pts[n - 1 - i];
        while (hull.size() > lower_size &&
               cross(hull[hull.size() - 2], hull.back(), p) <= 0)
            hull.pop_back();
        hull.push_back(p);
    }

    /* The last point is same as the first one, remove it */
    hull.pop_back();

    /* Compute perimeter */
    double perimeter = 0.0;
    const std::size_t m = hull.size();
    if (m > 1)
    {
#pragma omp parallel for reduction(+:perimeter) schedule(static)
        for (std::size_t i = 0; i < m; ++i)
            perimeter += dist(hull[i], hull[(i + 1) % m]);
    }
    return perimeter;
}
