/*
   Compute the new grid such that each cell is set to 1 iff exactly
   one of its 4 direct (up/down/left/right) neighbors in the *input*
   grid is 1.  The value of the cell itself is irrelevant.
   The grid is stored row‑major in a 1‑D vector.

   The implementation keeps the same semantics as the reference
   implementation but takes advantage of contiguous memory layout,
   explicit pointer arithmetic, and OpenMP parallelisation.
*/
void cellsXOR(std::vector<int> const& input,
              std::vector<int> &output,
              size_t N)
{
    /* ensure output has the required size */
    if (output.size() != N * N)
        output.resize(N * N);

#pragma omp parallel for schedule(static) collapse(2)
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = 0; j < N; ++j) {
            const int* row_up    = (i > 0)    ? &input[(i - 1) * N + j] : nullptr;
            const int* row_down  = (i + 1 < N) ? &input[(i + 1) * N + j] : nullptr;
            const int* col_left  = (j > 0)    ? &input[i * N + j - 1]   : nullptr;
            const int* col_right = (j + 1 < N) ? &input[i * N + j + 1]   : nullptr;

            int count = 0;
            if (row_up)   ++count;   // value is guaranteed 0 or 1
            if (row_down) ++count;
            if (col_left) ++count;
            if (col_right)++count;

            /* write result; the check is equivalent to (count == 1) */
            output[i * N + j] = (count == 1);
        }
    }
}
