struct Point {
    double x, y;
};

// Greedy (Monotone chain) convex hull
// O(n log n) time, O(n) space, deterministic order
void convexHull(std::vector<Point> const& points, std::vector<Point> &hull) {
    const std::size_t n = points.size();
    if (n < 3) {                 // trivial cases
        hull = points;
        return;
    }

    // Work on a copy so we can sort the points without touching the input
    std::vector<Point> pts = points;
    // Sort by x, then y
    std::sort(pts.begin(), pts.end(),
              [](const Point &a, const Point &b) {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // Cross product of (b-a) x (c-a)
    auto cross = [](const Point &a, const Point &b, const Point &c) -> double {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    };

    // The convex hull fits in at most 2*n points
    std::vector<Point> hullTemp;
    hullTemp.reserve(2 * n);

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (hullTemp.size() >= 2 &&
               cross(hullTemp[hullTemp.size() - 2],
                     hullTemp[hullTemp.size() - 1],
                     pts[i]) <= 0) {
            hullTemp.pop_back();
        }
        hullTemp.push_back(pts[i]);
    }

    // Build upper hull
    const std::size_t lowerSize = hullTemp.size();
    for (std::size_t i = n - 1; i > 0; --i) {
        while (hullTemp.size() > lowerSize + 1 &&
               cross(hullTemp[hullTemp.size() - 2],
                     hullTemp[hullTemp.size() - 1],
                     pts[i - 1]) <= 0) {
            hullTemp.pop_back();
        }
        hullTemp.push_back(pts[i - 1]);
    }

    // Remove duplicate last point
    hullTemp.pop_back();

    hull.swap(hullTemp);          // return the result
}
