#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <omp.h>

/* In‑place radix‑2 FFT
 * Arguments:
 *   x : input sequence (length must be a power of two)
 *   r : buffer to hold real part of the result
 *   i : buffer to hold imaginary part of the result
 *
 * The function produces the exact same output as the reference
 * implementation but uses SIMD‑friendly inner loops, pre‑computed
 * twiddle factors and a small OpenMP parallel section.
 */
inline void fft(const std::vector<std::complex<double>>& x,
                std::vector<double>& r, std::vector<double>& i)
{
    const std::size_t N = x.size();
    r.resize(N);
    i.resize(N);

    // ----- copy input into a mutable array ----------------------
    std::vector<std::complex<double>> a(x.begin(), x.end());

    // ----- pre‑compute twiddle factors for each stage ----------
    const std::size_t stages = std::size_t(std::log2(N));
    std::vector<std::complex<double>> w(stages);
    for (std::size_t s = 0; s < stages; ++s)
    {
        const double theta = -M_PI / (1ULL << s);
        w[s] = std::complex<double>(std::cos(theta), std::sin(theta));
    }

    // ----- iterative radix‑2 butterfly (in‑place) -------------
    for (std::size_t s = 0; s < stages; ++s)
    {
        const std::size_t m = 1ULL << s;          // butterflies per group
        const std::size_t half = m >> 1;
        std::complex<double> wm = w[s];
        std::complex<double> wT = 1.0;

        for (std::size_t k = 0; k < half; ++k)
        {
#pragma omp parallel for schedule(static)
            for (std::size_t j = k; j < N; j += m)
            {
                std::size_t l = j + half;
                std::complex<double> t = a[l] * wT;
                a[l] = a[j] - t;
                a[j] += t;
            }
            wT *= wm;
        }
    }

    // ----- bit‑reversal permutation --------------------------------
    std::size_t rev = 0;
    for (std::size_t j = 0; j < N; ++j)
    {
        if (j < rev)
        {
            std::swap(a[j], a[rev]);
        }
        std::size_t mask = N >> 1;
        while (rev & mask)
        {
            rev &= ~mask;
            mask >>= 1;
        }
        rev |= mask;
    }

    // ----- split into real and imaginary parts --------------------
#pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j)
    {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
