/*
 * Compute the rank of each element in the vector `x`.   
 * The result is stored in `ranks_` with the same size as `x`.  
 * This implementation uses a lightweight approach that achieves a low overhead
 * while retaining the exact semantics of the original algorithm.
 */
inline void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_) {
    const size_t n = x.size();
    if (n == 0) return;                         // guard against empty input

    // Build a vector of <value, original_index> pairs.
    std::vector<std::pair<float, size_t>> pairs;
    pairs.reserve(n);
    for (size_t i = 0; i < n; ++i) {
        pairs.emplace_back(x[i], i);
    }

    // Sort by value.  The comparison is a simple built‑in compare
    // for `float`, which GCC can inline efficiently.
    std::sort(pairs.begin(), pairs.end(),
              [](const auto& a, const auto& b) { return a.first < b.first; });

    // Convert sorted order back to ranks.
    for (size_t i = 0; i < n; ++i) {
        ranks_[pairs[i].second] = i;
    }
}
