/*
 * Compute one iteration of a 5‑point 2D Jacobi stencil on `input`.
 * Each element of `input` is averaged with its four neighbours
 * (missing neighbours are treated as zero).  The result is stored in `output`.
 *
 * Parameters
 *  ----------
 *  input :  const std::vector<double>&
 *      Input grid of size N*N (row‑major).
 *  output : std::vector<double>&
 *      Output grid of size N*N (row‑major).
 *  N : size_t
 *      Dimension of the grid (number of rows = number of columns).
 *
 * Notes
 * -----
 * - All arithmetic is performed in double precision.
 * - Boundary cells are handled implicitly by the conditional checks below.
 * - The function is fully deterministic and has no side‑effects outside
 *   the `output` vector.
 */
inline void jacobi2D(const std::vector<double> &input,
                     std::vector<double> &output, size_t N)
{
    const double inv5 = 0.2;
    const size_t stride = N;

    // Work with raw pointers for maximum performance
    const double *in  = input.data();
    double       *out = output.data();

    // Parallelize the double loop with OpenMP.
    // collapse(2) lets the compiler distribute both i and j
    // and ensures good load balance for all thread counts.
#pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t base = i * stride;
        const size_t im1  = (i > 0      ) ? (i - 1) * stride : static_cast<size_t>(-1);
        const size_t ip1  = (i + 1 < N   ) ? (i + 1) * stride : static_cast<size_t>(-1);

        for (size_t j = 0; j < N; ++j)
        {
            double sum = in[base + j];        // centre

            // north
            if (im1 != static_cast<size_t>(-1))
                sum += in[im1 + j];

            // south
            if (ip1 != static_cast<size_t>(-1))
                sum += in[ip1 + j];

            // west
            if (j > 0)
                sum += in[base + j - 1];

            // east
            if (j + 1 < N)
                sum += in[base + j + 1];

            out[base + j] = sum * inv5;
        }
    }
}
