/*
   Multiply the matrix A by the vector x, storing the result in y.
   A is an MxN matrix stored in row-major order, x has N elements,
   and y must have M elements.  The implementation is identical to the
   reference implementation but uses pointer arithmetic, loop vectorisation
   and OpenMP parallelisation to maximise performance on modern x86‑64
   hardware.
 */
void gemv(std::vector<double> const& A,
          std::vector<double> const& x,
          std::vector<double>&          y,
          size_t                        M,
          size_t                        N)
{
    const double* const Ap = A.data();
    const double* const xp = x.data();
    double*          const yp = y.data();

    /* Parallelise outer loop; each iteration writes to a distinct element
       of y, guaranteeing thread safety.  The inner loop is vectorised
       with the `omp simd` pragma.  Use a static schedule to minimise
       overhead when M is large. */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; ++i)
    {
        const double* const row = Ap + i * N;
        double sum = 0.0;

        #pragma omp simd
        for (size_t j = 0; j < N; ++j)
        {
            sum += row[j] * xp[j];
        }

        yp[i] = sum;
    }
}
