constexpr double PI = 3.14159265358979323846;

static void bit_reverse_permutation(std::vector<std::complex<double>>& data)
{
    const std::size_t n = data.size();
    std::size_t m = static_cast<std::size_t>(std::log2(n));

    for (std::size_t i = 0; i < n; ++i) {
        std::size_t j = i;
        // Reverse bits
        j = ((j & 0xaaaaaaaaul) >> 1) | ((j & 0x55555555ul) << 1);
        j = ((j & 0xccccccccul) >> 2) | ((j & 0x33333333ul) << 2);
        j = ((j & 0xf0f0f0f0ul) >> 4) | ((j & 0x0f0f0f0ful) << 4);
        j = ((j & 0xff00ff00ul) >> 8) | ((j & 0x00ff00fful) << 8);
        j = ((j >> 16) | (j << 16)) >> (32 - m);
        if (j > i) std::swap(data[i], data[j]);
    }
}

// Pre-compute twiddle factors for all stages
static void build_twiddles(std::vector<std::vector<std::complex<double>>>& twiddles,
                           std::size_t n)
{
    std::size_t stages = static_cast<std::size_t>(std::log2(n));
    twiddles.resize(stages);

    for (std::size_t s = 0; s < stages; ++s) {
        std::size_t m = 1ull << (s + 1);
        std::size_t half = m >> 1;
        twiddles[s].resize(half);
        double theta = -PI / half;
        for (std::size_t k = 0; k < half; ++k) {
            double real = std::cos(k * theta);
            double imag = std::sin(k * theta);
            twiddles[s][k] = std::complex<double>(real, imag);
        }
    }
}

// Iterative radix‑2 Cooley‑Tukey FFT, in‑place
static void fft_inplace(std::vector<std::complex<double>>& data)
{
    const std::size_t n = data.size();
    bit_reverse_permutation(data);

    std::vector<std::vector<std::complex<double>>> twiddles;
    build_twiddles(twiddles, n);

    #pragma omp parallel for schedule(static)
    for (std::size_t s = 0; s < twiddles.size(); ++s) {
        std::size_t m = 1ull << (s + 1);
        std::size_t half = m >> 1;
        for (std::size_t k = 0; k < n; k += m) {
            for (std::size_t j = 0; j < half; ++j) {
                std::size_t a = k + j;
                std::size_t b = a + half;
                std::complex<double> t = data[a] - data[b];
                data[a] += data[b];
                data[b] = t * twiddles[s][j];
            }
        }
    }
}

// Public API
void fft(const std::vector<std::complex<double>>& x, std::vector<std::complex<double>>& output)
{
    output = x;                 // copy input
    if (output.size() == 0) return;
    fft_inplace(output);
}
