// 3x3 edge detection kernel (static for fast access)
static constexpr int edgeKernel[3][3] = {
    {-1, -1, -1},
    {-1,  8, -1},
    {-1, -1, -1}
};

/*
Convolve the edge kernel with a grayscale image.
imageIn : input image (NxN) in row‑major order
imageOut: output image (NxN), must be pre‑allocated
N       : image dimension
*/
inline void convolveKernel(const std::vector<int> &imageIn,
                           std::vector<int> &imageOut,
                           size_t N)
{
    if (N == 0) return;

    // Work with raw pointers for maximal speed
    const int *in  = imageIn.data();
    int       *out = imageOut.data();

    // Parallelise outer loops with OpenMP
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t iN = i * N;
        for (size_t j = 0; j < N; ++j) {
            int sum = 0;

            // Accumulate contributions from the 3x3 neighbourhood
            // Treat border pixels with zero‑padding by checking bounds
            int k0 = (int)i - 1, k1 = (int)i, k2 = (int)i + 1;
            int l0 = (int)j - 1, l1 = (int)j, l2 = (int)j + 1;

            // Row k0
            if (k0 >= 0) {
                sum += (in[k0*N + (l0>=0?l0:0)]   * edgeKernel[0][0]) +
                       (in[k0*N + (l1>=0?l1:0)]   * edgeKernel[0][1]) +
                       (in[k0*N + (l2<N  ?l2:0)]   * edgeKernel[0][2]);
            }
            // Row k1
            if (k1 >= 0 && k1 < (int)N) {
                sum += (in[k1*N + (l0>=0?l0:0)]   * edgeKernel[1][0]) +
                       (in[k1*N + (l1>=0?l1:0)]   * edgeKernel[1][1]) +
                       (in[k1*N + (l2<N  ?l2:0)]   * edgeKernel[1][2]);
            }
            // Row k2
            if (k2 < (int)N) {
                sum += (in[k2*N + (l0>=0?l0:0)]   * edgeKernel[2][0]) +
                       (in[k2*N + (l1>=0?l1:0)]   * edgeKernel[2][1]) +
                       (in[k2*N + (l2<N  ?l2:0)]   * edgeKernel[2][2]);
            }

            // Clip to 0..255
            out[iN + j] = static_cast<int>(std::max(0, std::min(255, sum)));
        }
    }
}
