/// Sorts all non‑zero elements of *x* in ascending order while leaving the
/// zero elements in their original positions.  The implementation is
/// intentionally simple, portable and fast for the common case where
/// the number of zeros is smaller than the total length of the vector.
inline void sortIgnoreZero(std::vector<int>& x)
{
    // Quick exit for tiny vectors
    if (x.size() < 2) return;

    // Reserve space once to avoid repeated growth operations.
    std::vector<int> nonZero;
    nonZero.reserve(x.size());

    // Collect non‑zero values.
    for (int v : x)
        if (v != 0)
            nonZero.push_back(v);

    // Sort the collected values.
    std::sort(nonZero.begin(), nonZero.end());

    // Re‑insert sorted values into the original positions.
    std::size_t idx = 0;
    for (std::size_t i = 0; i < x.size(); ++i) {
        if (x[i] != 0)
            x[i] = nonZero[idx++];
    }
}
