/*
   Multiply the matrix A by B.  The matrices are stored in row‑major
   order.
     A : M x K
     B : K x N
     C : M x N   (C is assumed to be zeroed by the caller)

   The routine is heavily tuned for 64‑bit x86 with SSE/AVX support.
   It uses classic cache blocking and OpenMP parallelism while keeping the
   original behaviour unchanged.
*/
inline void gemm(const std::vector<double> &A,
                 const std::vector<double> &B,
                 std::vector<double>       &C,
                 const size_t M,
                 const size_t K,
                 const size_t N)
{
    /* cache block sizes tuned for a typical L1/L2 configuration */
    constexpr size_t BLOCK_M = 64;   // rows of A / C
    constexpr size_t BLOCK_K = 64;   // columns of A / rows of B
    constexpr size_t BLOCK_N = 64;   // columns of B / C

    // Parallelise over the i dimension.  The work is automatically
    // divided among the 8 threads on the target machine.
    #pragma omp parallel for schedule(static)
    for (size_t bi = 0; bi < M; bi += BLOCK_M) {
        const size_t i_end = (bi + BLOCK_M <= M) ? (bi + BLOCK_M) : M;
        for (size_t bk = 0; bk < K; bk += BLOCK_K) {
            const size_t k_end = (bk + BLOCK_K <= K) ? (bk + BLOCK_K) : K;
            for (size_t bn = 0; bn < N; bn += BLOCK_N) {
                const size_t n_end = (bn + BLOCK_N <= N) ? (bn + BLOCK_N) : N;

                for (size_t i = bi; i < i_end; ++i) {
                    const size_t iK = i * K;      // base index for A row i
                    const size_t iN = i * N;      // base index for C row i
                    for (size_t k = bk; k < k_end; ++k) {
                        const double a_val = A[iK + k];
                        const size_t kN = k * N;  // base index for B row k
                        for (size_t j = bn; j < n_end; ++j) {
                            // Use ivdep to hint that there are no
                            // inter‑iteration dependencies.
                            #pragma GCC ivdep
                            C[iN + j] += a_val * B[kN + j];
                        }
                    }
                }
            }
        }
    }
}
