01_dense_la_solve:
```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Solve the linear system Ax = b for x.
 * A is an NxN matrix in row-major order.
 * x and b have N elements.
 *
 * Behaviour is identical to the reference implementation and
 * requires no partial pivoting.
 */
void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    // Defensive copy of A and b to avoid modifying the originals
    std::vector<double> a(A);           // working copy of A
    std::vector<double> bb(b);          // working copy of b

    // ------------------------------------------------------------
    // 1. Gaussian elimination (forward elimination)
    // ------------------------------------------------------------
    for (size_t i = 0; i + 1 < N; ++i) {
        double const pivot = a[i * N + i];
        if (pivot == 0.0)            // singular matrix – leave x unchanged
            return;

        // Parallelise the inner loop over rows j
        #pragma omp parallel for schedule(static)
        for (size_t j = i + 1; j < N; ++j) {
            double const factor = a[j * N + i] / pivot;
            // update the remaining columns of row j
            double *row_j = &a[j * N + i];
            double *row_i = &a[i * N + i];
            for (size_t k = i; k < N; ++k)
                row_j[k - i] -= factor * row_i[k - i];
            bb[j] -= factor * bb[i];
        }
    }

    // ------------------------------------------------------------
    // 2. Back substitution
    // ------------------------------------------------------------
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        double const *row = &a[i * N];
        for (size_t j = i + 1; j < N; ++j)
            sum += row[j] * x[j];
        x[i] = (bb[i] - sum) / a[i * N + i];
    }
}
```
This implementation keeps the exact mathematical result while:

1. Using blocking‑free, pointer‑style access for cache friendliness.
2. Parallelising the independent row updates with OpenMP (`-fopenmp`), which gives a significant speedup on multicore CPUs.
3. Avoiding unnecessary temporary vectors inside loops.
4. Maintaining the same function signature and behaviour as the original code.

