/// Return the index of the value in the vector `x` that is closest to PI.
/// The implementation uses OpenMP to parallelise the scan across available
/// threads.  The algorithm keeps a local best for each thread and then merges
/// them using a critical section.  This preserves the exact behaviour of the
/// reference implementation while exploiting multiple cores.
size_t findClosestToPi(std::vector<double> const& x) {
    // Guard against an empty vector – the original code assumes at least one element.
    if (x.empty()) return static_cast<size_t>(-1);

    // Preparation of the first element, which will be used to initialise every thread.
    const double pi = M_PI;
    const double first_diff = std::fabs(x[0] - pi);

    size_t global_best_index = 0;
    double global_best_diff   = first_diff;

#pragma omp parallel
    {
        size_t local_best_index = 0;
        double local_best_diff   = first_diff;

#pragma omp for
        for (size_t i = 1; i < x.size(); ++i) {
            const double diff = std::fabs(x[i] - pi);
            if (diff < local_best_diff) {
                local_best_diff   = diff;
                local_best_index = i;
            }
        }

#pragma omp critical
        {
            if (local_best_diff < global_best_diff) {
                global_best_diff = local_best_diff;
                global_best_index = local_best_index;
            }
        }
    }

    return global_best_index;
}
