#include <omp.h>

#if !defined(M_PI)
#  define M_PI 3.14159265358979323846
#endif

/* ------------------------------------------------------------------
   Optimised in‑place radix‑2 Cooley–Tukey FFT / inverse FFT
   ------------------------------------------------------------------ */

inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    // --------------------------------------------------------------
    // 1. Cooley–Tukey decimation‑in‑frequency
    // --------------------------------------------------------------
    const double theta = M_PI / static_cast<double>(N);
    std::complex<double> w( std::cos(theta) , -std::cos(theta) );   // φ_T
    std::complex<double> T(1.0, 0.0);
    std::size_t k = N / 2;             // current sub‑array length
    std::size_t n = N;                 // stride between elements

    while (k >= 2) {
        n >>= 1;                       // n  = k
        w = w * w;                     // w = φ_T^2

        #pragma omp parallel for schedule(static) collapse(2)
        for (std::size_t l = 0; l < k; ++l) {
            T = std::complex<double>(1.0, 0.0);
            for (std::size_t a = l; a < N; a += n) {
                const std::size_t b = a + k;
                std::complex<double> t = x[a] - x[b];
                x[a]     += x[b];
                x[b]      = t * T;
                T        *= w;
            }
        }
        k >>= 1;
    }

    // --------------------------------------------------------------
    // 2. Bit‑reversal permutation
    // --------------------------------------------------------------
    const std::size_t log2N = static_cast<std::size_t>(std::log2(N));
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t x = i;
        x = ((x & 0xaaaaaaaaULL) >>  1) | ((x & 0x55555555ULL) <<  1);
        x = ((x & 0xccccccccULL) >>  2) | ((x & 0x33333333ULL) <<  2);
        x = ((x & 0xf0f0f0f0ULL) >>  4) | ((x & 0x0f0f0f0fULL) <<  4);
        x = ((x & 0xff00ff00ULL) >>  8) | ((x & 0x00ff00ffULL) <<  8);
        x = ((x >> 16) | (x << 16)) >> (32 - log2N);
        rev[i] = x;
    }

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t j = rev[i];
        if (j > i) std::swap(x[i], x[j]);
    }
}

/* ------------------------------------------------------------------
   Inverse FFT (in‑place)
   ------------------------------------------------------------------ */
inline void ifft(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    // 1. conjugate
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) x[i] = std::conj(x[i]);

    // 2. forward FFT
    fft_helper(x);

    // 3. conjugate again
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) x[i] = std::conj(x[i]);

    // 4. scale by 1/N
    const double invN = 1.0 / static_cast<double>(N);
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) x[i] *= invN;
}
