#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>
#include <cstdint>
#include <cstring>   // for memset

//=============================================================================
// Optimised FFT implementation that produces the same results as the
// reference routine.
//
// * Uses a pre‑computed bit‑reversal table (cached the first time the
//   function is called).
// * Performs the radix‑2 Cooley–Tukey butterfly iteratively, using
//   complex‑number arithmetic that exploits compiler vectorisers.
// * Parallelises the decimation (bit‑reversal) and final conjugation
//   stages with OpenMP.
// * All floating‑point calculations use the hardware double‑precision
//   type so the output matches the reference exactly.
//=============================================================================
static inline std::uint32_t next_power_of_two(std::uint32_t x)
{
    return x > 1 ? (1u << (32 - __builtin_clz(x-1))) : 1u;
}

static inline std::uint32_t log2_uint32(std::uint32_t x)
{
    return 31 - __builtin_clz(x);
}

// Pre‑computed table of bit‑reversed indices for a given size.
// It is lazily initialised on the first call with a particular N.
static struct BitReverseCache
{
    std::vector<std::uint32_t> table;
    std::uint32_t size{0};

    void init(std::uint32_t N)
    {
        size = N;
        table.resize(N);
        std::uint32_t m = log2_uint32(N);
        for (std::uint32_t i = 0; i < N; ++i)
        {
            std::uint32_t x = i;
            x = ((x & 0xAAAAAAAAu) >> 1) | ((x & 0x55555555u) << 1);
            x = ((x & 0xCCCCCCCCu) >> 2) | ((x & 0x33333333u) << 2);
            x = ((x & 0xF0F0F0F0u) >> 4) | ((x & 0x0F0F0F0Fu) << 4);
            x = ((x & 0xFF00FF00u) >> 8) | ((x & 0x00FF00FFu) << 8);
            x = (x >> 16) | (x << 16);
            table[i] = x >> (32 - m);
        }
    }
} gBitRevCache;

//=============================================================================
inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::uint32_t N = static_cast<std::uint32_t>(x.size());
    if (N == 0) return;
    if (N == 1) { x[0] = std::conj(x[0]); return; }

    // Initialise bit‑reversal table on first use for this size.
    if (gBitRevCache.size != N) gBitRevCache.init(N);
    const std::uint32_t* rev = gBitRevCache.table.data();

    //-----------------------------------------------------------------------
    // 1) Decimation‑in‑time (bit‑reversal permutation)
    // Parallelise over the entire array.
    //-----------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (std::uint32_t i = 0; i < N; ++i)
    {
        std::uint32_t j = rev[i];
        if (j > i) std::swap(x[i], x[j]);        // only one swap per pair
    }

    //-----------------------------------------------------------------------
    // 2) In‑place radix‑2 Cooley–Tukey FFT (iterative, stage → stage)
    //    The outer loop controls the number of stages.
    //-----------------------------------------------------------------------
    const double PI = acos(-1.0);
    std::complex<double> w_m = std::complex<double>(-1.0, 0.0);  // exp(-pi*i)

    for (std::uint32_t s = 1; s <= log2_uint32(N); ++s)
    {
        const std::uint32_t m = 1u << s;          // block size
        const std::uint32_t m2 = m >> 1;          // half block

        // Pre‑compute the primitive m‑th root of unity.
        const double theta = -2.0 * PI / m;
        const std::complex<double> w = std::complex<double>(cos(theta), sin(theta));

        std::complex<double> w_n = 1.0;           // current power of w

        // Stage loop: iterate over all blocks.
        // Parallelise over the outermost (block) dimension to benefit
        // from NUMA locality on multi‑core CPUs.
        #pragma omp parallel for schedule(static)
        for (std::uint32_t k = 0; k < N; k += m)
        {
            std::complex<double> w_curr = 1.0;    // w^0 for each block
            for (std::uint32_t j = 0; j < m2; ++j)
            {
                std::uint32_t a = k + j;
                std::uint32_t b = a + m2;
                std::complex<double> t = x[b] * w_curr;
                x[b] = x[a] - t;
                x[a] += t;
                w_curr *= w;
            }
        }
    }

    //-----------------------------------------------------------------------
    // 3) Conjugate every element.
    // Parallelised for extra speed on large vectors.
    //-----------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (std::uint32_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
